import type {
  AuthResponse,
  SignupRequest,
  LoginRequest,
  CanvasSummary,
  CanvasDetail,
  CreateCanvasRequest,
  InviteRequest,
  ErrorResponse,
} from "./types.ts";

function getToken(): string | null {
  return localStorage.getItem("token");
}

function authHeaders(): Record<string, string> {
  const token = getToken();
  return token ? { Authorization: `Bearer ${token}` } : {};
}

async function request<T>(
  method: string,
  path: string,
  body?: unknown
): Promise<T> {
  const headers: Record<string, string> = {
    "Content-Type": "application/json",
    ...authHeaders(),
  };
  const res = await fetch(path, {
    method,
    headers,
    body: body ? JSON.stringify(body) : undefined,
  });
  if (!res.ok) {
    const err: ErrorResponse = await res.json().catch(() => ({ error: "unknown" }));
    throw new ApiError(res.status, err.error);
  }
  return res.json() as Promise<T>;
}

export class ApiError extends Error {
  status: number;
  code: string;
  constructor(status: number, code: string) {
    super(code);
    this.status = status;
    this.code = code;
  }
}

export async function signup(data: SignupRequest): Promise<AuthResponse> {
  return request<AuthResponse>("POST", "/api/auth/signup", data);
}

export async function login(data: LoginRequest): Promise<AuthResponse> {
  return request<AuthResponse>("POST", "/api/auth/login", data);
}

export async function getCanvases(): Promise<CanvasSummary[]> {
  return request<CanvasSummary[]>("GET", "/api/canvases");
}

export async function createCanvas(data: CreateCanvasRequest): Promise<CanvasSummary> {
  return request<CanvasSummary>("POST", "/api/canvases", data);
}

export async function getCanvasDetail(canvasId: string): Promise<CanvasDetail> {
  return request<CanvasDetail>("GET", `/api/canvases/${canvasId}`);
}

export async function inviteToCanvas(
  canvasId: string,
  data: InviteRequest
): Promise<{ ok: true }> {
  return request<{ ok: true }>("POST", `/api/canvases/${canvasId}/invite`, data);
}

import type { AuthUser } from "./types.ts";

const TOKEN_KEY = "token";
const USER_KEY = "user";

export function getStoredToken(): string | null {
  return localStorage.getItem(TOKEN_KEY);
}

export function getStoredUser(): AuthUser | null {
  const raw = localStorage.getItem(USER_KEY);
  if (!raw) return null;
  try {
    return JSON.parse(raw) as AuthUser;
  } catch {
    return null;
  }
}

export function storeAuth(token: string, user: AuthUser): void {
  localStorage.setItem(TOKEN_KEY, token);
  localStorage.setItem(USER_KEY, JSON.stringify(user));
}

export function clearAuth(): void {
  localStorage.removeItem(TOKEN_KEY);
  localStorage.removeItem(USER_KEY);
}

export function isAuthenticated(): boolean {
  return getStoredToken() !== null;
}

import type { Shape } from "./types.ts";

export interface CursorInfo {
  x: number;
  y: number;
  username: string;
  color: string;
}

export interface SelectionState {
  shapeId: string;
  handles: { x: number; y: number; w: number; h: number }[];
}

const HANDLE_SIZE = 8;

export function renderScene(
  ctx: CanvasRenderingContext2D,
  shapes: Shape[],
  selection: SelectionState | null,
  cursors: Map<string, CursorInfo>,
  previewShape: Shape | null,
  canvasWidth: number,
  canvasHeight: number,
  dpr: number
): void {
  ctx.save();
  ctx.setTransform(dpr, 0, 0, dpr, 0, 0);
  ctx.clearRect(0, 0, canvasWidth, canvasHeight);

  // Draw all shapes
  for (const shape of shapes) {
    drawShape(ctx, shape);
  }

  // Draw preview shape
  if (previewShape) {
    drawShape(ctx, previewShape);
  }

  // Draw selection
  if (selection) {
    const shape = shapes.find((s) => s.id === selection.shapeId);
    if (shape) {
      drawSelectionBox(ctx, shape);
    }
  }

  // Draw remote cursors
  for (const [, cursor] of cursors) {
    drawCursor(ctx, cursor);
  }

  ctx.restore();
}

function drawShape(ctx: CanvasRenderingContext2D, shape: Shape): void {
  ctx.save();
  ctx.fillStyle = shape.fill || "transparent";
  ctx.strokeStyle = shape.stroke || "#000000";
  ctx.lineWidth = shape.strokeWidth;

  switch (shape.type) {
    case "rectangle":
      if (shape.fill) {
        ctx.fillRect(shape.x, shape.y, shape.width, shape.height);
      }
      ctx.strokeRect(shape.x, shape.y, shape.width, shape.height);
      break;

    case "ellipse": {
      const cx = shape.x + shape.width / 2;
      const cy = shape.y + shape.height / 2;
      const rx = Math.abs(shape.width / 2);
      const ry = Math.abs(shape.height / 2);
      ctx.beginPath();
      ctx.ellipse(cx, cy, rx, ry, 0, 0, Math.PI * 2);
      if (shape.fill) {
        ctx.fill();
      }
      ctx.stroke();
      break;
    }

    case "line":
      ctx.beginPath();
      ctx.moveTo(shape.x, shape.y);
      ctx.lineTo(shape.x + shape.width, shape.y + shape.height);
      ctx.stroke();
      break;

    case "text": {
      const fontSize = shape.fontSize || 16;
      ctx.font = `${fontSize}px sans-serif`;
      ctx.fillStyle = shape.fill || "#000000";
      ctx.fillText(shape.text || "", shape.x, shape.y + fontSize);
      if (shape.stroke && shape.strokeWidth > 0) {
        ctx.strokeStyle = shape.stroke;
        ctx.lineWidth = shape.strokeWidth;
        ctx.strokeText(shape.text || "", shape.x, shape.y + fontSize);
      }
      break;
    }
  }

  ctx.restore();
}

function drawSelectionBox(ctx: CanvasRenderingContext2D, shape: Shape): void {
  ctx.save();
  ctx.strokeStyle = "#0088ff";
  ctx.lineWidth = 1;
  ctx.setLineDash([4, 4]);
  ctx.strokeRect(shape.x - 2, shape.y - 2, shape.width + 4, shape.height + 4);
  ctx.setLineDash([]);

  // Draw handles at corners
  const handles = getHandlePositions(shape);
  ctx.fillStyle = "#0088ff";
  for (const h of handles) {
    ctx.fillRect(h.x, h.y, h.w, h.h);
  }

  ctx.restore();
}

export function getHandlePositions(
  shape: Shape
): { x: number; y: number; w: number; h: number; corner: string }[] {
  const hs = HANDLE_SIZE;
  const half = hs / 2;
  return [
    { x: shape.x - half - 2, y: shape.y - half - 2, w: hs, h: hs, corner: "nw" },
    { x: shape.x + shape.width - half + 2, y: shape.y - half - 2, w: hs, h: hs, corner: "ne" },
    { x: shape.x - half - 2, y: shape.y + shape.height - half + 2, w: hs, h: hs, corner: "sw" },
    {
      x: shape.x + shape.width - half + 2,
      y: shape.y + shape.height - half + 2,
      w: hs,
      h: hs,
      corner: "se",
    },
  ];
}

function drawCursor(ctx: CanvasRenderingContext2D, cursor: CursorInfo): void {
  ctx.save();

  // Draw cursor arrow
  ctx.fillStyle = cursor.color;
  ctx.strokeStyle = "#ffffff";
  ctx.lineWidth = 1;

  ctx.beginPath();
  ctx.moveTo(cursor.x, cursor.y);
  ctx.lineTo(cursor.x, cursor.y + 16);
  ctx.lineTo(cursor.x + 5, cursor.y + 12);
  ctx.lineTo(cursor.x + 10, cursor.y + 12);
  ctx.closePath();
  ctx.fill();
  ctx.stroke();

  // Draw username label
  ctx.font = "11px sans-serif";
  const metrics = ctx.measureText(cursor.username);
  const labelX = cursor.x + 12;
  const labelY = cursor.y + 10;
  const padding = 3;

  ctx.fillStyle = cursor.color;
  ctx.beginPath();
  ctx.roundRect(
    labelX - padding,
    labelY - 10 - padding,
    metrics.width + padding * 2,
    14 + padding * 2,
    3
  );
  ctx.fill();

  ctx.fillStyle = "#ffffff";
  ctx.fillText(cursor.username, labelX, labelY);

  ctx.restore();
}

export function hitTest(shapes: Shape[], x: number, y: number): Shape | null {
  // Iterate in reverse z-order (topmost first)
  for (let i = shapes.length - 1; i >= 0; i--) {
    const s = shapes[i];
    if (isPointInShape(s, x, y)) {
      return s;
    }
  }
  return null;
}

function isPointInShape(shape: Shape, px: number, py: number): boolean {
  const margin = 4;
  switch (shape.type) {
    case "rectangle":
    case "text":
      return (
        px >= shape.x - margin &&
        px <= shape.x + shape.width + margin &&
        py >= shape.y - margin &&
        py <= shape.y + shape.height + margin
      );

    case "ellipse": {
      const cx = shape.x + shape.width / 2;
      const cy = shape.y + shape.height / 2;
      const rx = Math.abs(shape.width / 2) + margin;
      const ry = Math.abs(shape.height / 2) + margin;
      if (rx === 0 || ry === 0) return false;
      const dx = px - cx;
      const dy = py - cy;
      return (dx * dx) / (rx * rx) + (dy * dy) / (ry * ry) <= 1;
    }

    case "line": {
      // Check distance from point to line segment
      const x1 = shape.x;
      const y1 = shape.y;
      const x2 = shape.x + shape.width;
      const y2 = shape.y + shape.height;
      const dist = distToSegment(px, py, x1, y1, x2, y2);
      return dist <= shape.strokeWidth / 2 + margin + 4;
    }

    default:
      return false;
  }
}

function distToSegment(
  px: number,
  py: number,
  x1: number,
  y1: number,
  x2: number,
  y2: number
): number {
  const dx = x2 - x1;
  const dy = y2 - y1;
  const lenSq = dx * dx + dy * dy;
  if (lenSq === 0) return Math.sqrt((px - x1) ** 2 + (py - y1) ** 2);
  let t = ((px - x1) * dx + (py - y1) * dy) / lenSq;
  t = Math.max(0, Math.min(1, t));
  const projX = x1 + t * dx;
  const projY = y1 + t * dy;
  return Math.sqrt((px - projX) ** 2 + (py - projY) ** 2);
}

export function hitTestHandle(
  shape: Shape,
  x: number,
  y: number
): string | null {
  const handles = getHandlePositions(shape);
  for (const h of handles) {
    if (x >= h.x && x <= h.x + h.w && y >= h.y && y <= h.y + h.h) {
      return h.corner;
    }
  }
  return null;
}

import type { Shape, Operation, ShapePatch } from "./types.ts";

/**
 * Apply an operation to a shapes array, returning a new array.
 */
export function applyOp(shapes: Shape[], op: Operation): Shape[] {
  switch (op.kind) {
    case "add":
      return [...shapes, op.shape];
    case "update":
      return shapes.map((s) =>
        s.id === op.shapeId ? { ...s, ...op.props } : s
      );
    case "delete":
      return shapes.filter((s) => s.id !== op.shapeId);
  }
}

/**
 * Build the reverse operation for undo.
 * For update ops, only captures the fields that were changed (field-level LWW).
 */
export function reverseOp(op: Operation, shapes: Shape[]): Operation {
  switch (op.kind) {
    case "add":
      return { kind: "delete", shapeId: op.shape.id };

    case "delete": {
      const shape = shapes.find((s) => s.id === op.shapeId);
      if (!shape) {
        // Shape already gone, create a no-op add with a placeholder
        // This shouldn't happen in normal flow
        return {
          kind: "add",
          shape: {
            id: op.shapeId,
            type: "rectangle",
            x: 0,
            y: 0,
            width: 0,
            height: 0,
            fill: "",
            stroke: "#000000",
            strokeWidth: 2,
          },
        };
      }
      return { kind: "add", shape: { ...shape } };
    }

    case "update": {
      const shape = shapes.find((s) => s.id === op.shapeId);
      if (!shape) {
        // Shape not found; return the same update (will be no-op on server)
        return op;
      }
      // Only capture the old values of fields that are being changed
      const reverseProps: ShapePatch = {};
      for (const key of Object.keys(op.props) as (keyof ShapePatch)[]) {
        if (op.props[key] !== undefined) {
          (reverseProps as Record<string, unknown>)[key] = shape[key];
        }
      }
      return { kind: "update", shapeId: op.shapeId, props: reverseProps };
    }
  }
}

import { useState } from "react";
import { signup, login, ApiError } from "../api.ts";
import { storeAuth } from "../authStore.ts";

interface AuthProps {
  initialMode: "login" | "signup";
  onAuth: () => void;
}

export default function Auth({ initialMode, onAuth }: AuthProps) {
  const [mode, setMode] = useState<"login" | "signup">(initialMode);
  const [username, setUsername] = useState("");
  const [email, setEmail] = useState("");
  const [password, setPassword] = useState("");
  const [error, setError] = useState("");
  const [loading, setLoading] = useState(false);

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    setError("");
    setLoading(true);
    try {
      if (mode === "signup") {
        const res = await signup({ username, email, password });
        storeAuth(res.token, res.user);
      } else {
        const res = await login({ username, password });
        storeAuth(res.token, res.user);
      }
      onAuth();
    } catch (err) {
      if (err instanceof ApiError) {
        const messages: Record<string, string> = {
          username_taken: "Username is already taken.",
          email_taken: "Email is already in use.",
          invalid_credentials: "Invalid username or password.",
        };
        setError(messages[err.code] || err.code);
      } else {
        setError("Network error. Please try again.");
      }
    } finally {
      setLoading(false);
    }
  };

  return (
    <div style={styles.container}>
      <div style={styles.card}>
        <h1 style={styles.title}>Whiteboard</h1>
        <h2 style={styles.subtitle}>
          {mode === "login" ? "Log In" : "Sign Up"}
        </h2>
        <form onSubmit={handleSubmit} style={styles.form}>
          <label style={styles.label}>
            Username
            <input
              style={styles.input}
              type="text"
              value={username}
              onChange={(e) => setUsername(e.target.value)}
              required
              autoComplete="username"
            />
          </label>
          {mode === "signup" && (
            <label style={styles.label}>
              Email
              <input
                style={styles.input}
                type="email"
                value={email}
                onChange={(e) => setEmail(e.target.value)}
                required
                autoComplete="email"
              />
            </label>
          )}
          <label style={styles.label}>
            Password
            <input
              style={styles.input}
              type="password"
              value={password}
              onChange={(e) => setPassword(e.target.value)}
              required
              minLength={4}
              autoComplete={
                mode === "signup" ? "new-password" : "current-password"
              }
            />
          </label>
          {error && <div style={styles.error}>{error}</div>}
          <button type="submit" style={styles.button} disabled={loading}>
            {loading
              ? "Please wait..."
              : mode === "login"
                ? "Log In"
                : "Sign Up"}
          </button>
        </form>
        <p style={styles.switchText}>
          {mode === "login" ? (
            <>
              Don&apos;t have an account?{" "}
              <button
                style={styles.link}
                onClick={() => {
                  setMode("signup");
                  setError("");
                }}
              >
                Sign up
              </button>
            </>
          ) : (
            <>
              Already have an account?{" "}
              <button
                style={styles.link}
                onClick={() => {
                  setMode("login");
                  setError("");
                }}
              >
                Log in
              </button>
            </>
          )}
        </p>
      </div>
    </div>
  );
}

