import { useState, useEffect } from "react";
import type { CanvasSummary } from "../types.ts";
import { getCanvases, createCanvas, ApiError } from "../api.ts";
import { clearAuth, getStoredUser } from "../authStore.ts";

interface CanvasListProps {
  onSelectCanvas: (canvasId: string) => void;
  onLogout: () => void;
}

export default function CanvasList({
  onSelectCanvas,
  onLogout,
}: CanvasListProps) {
  const [canvases, setCanvases] = useState<CanvasSummary[]>([]);
  const [newName, setNewName] = useState("");
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState("");
  const [creating, setCreating] = useState(false);
  const user = getStoredUser();

  useEffect(() => {
    let cancelled = false;
    getCanvases()
      .then((data) => {
        if (!cancelled) {
          setCanvases(data);
          setLoading(false);
        }
      })
      .catch((err) => {
        if (!cancelled) {
          if (err instanceof ApiError && err.status === 401) {
            handleLogout();
          } else {
            setError("Failed to load canvases.");
            setLoading(false);
          }
        }
      });
    return () => {
      cancelled = true;
    };
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, []);

  const handleLogout = () => {
    clearAuth();
    onLogout();
  };

  const handleCreate = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!newName.trim()) return;
    setCreating(true);
    setError("");
    try {
      const canvas = await createCanvas({ name: newName.trim() });
      setCanvases((prev) => [...prev, canvas]);
      setNewName("");
    } catch (err) {
      if (err instanceof ApiError && err.status === 401) {
        handleLogout();
      } else {
        setError("Failed to create canvas.");
      }
    } finally {
      setCreating(false);
    }
  };

  return (
    <div style={styles.container}>
      <div style={styles.header}>
        <h1 style={styles.title}>My Canvases</h1>
        <div style={styles.headerRight}>
          <span style={styles.username}>{user?.username}</span>
          <button style={styles.logoutBtn} onClick={handleLogout}>
            Log out
          </button>
        </div>
      </div>

      <form onSubmit={handleCreate} style={styles.createForm}>
        <input
          style={styles.input}
          type="text"
          placeholder="New canvas name..."
          value={newName}
          onChange={(e) => setNewName(e.target.value)}
          required
        />
        <button type="submit" style={styles.createBtn} disabled={creating}>
          {creating ? "Creating..." : "Create Canvas"}
        </button>
      </form>

      {error && <div style={styles.error}>{error}</div>}

      {loading ? (
        <p style={styles.emptyText}>Loading...</p>
      ) : canvases.length === 0 ? (
        <p style={styles.emptyText}>
          No canvases yet. Create one to get started.
        </p>
      ) : (
        <div style={styles.list}>
          {canvases.map((c) => (
            <button
              key={c.id}
              style={styles.canvasItem}
              onClick={() => onSelectCanvas(c.id)}
            >
              <span style={styles.canvasName}>{c.name}</span>
              <span style={styles.canvasDate}>
                {new Date(c.createdAt).toLocaleDateString()}
              </span>
            </button>
          ))}
        </div>
      )}
    </div>
  );
}

