1	import { useState, useEffect } from "react";
2	import { isAuthenticated, clearAuth } from "./authStore.ts";
3	import Auth from "./components/Auth.tsx";
4	import CanvasList from "./components/CanvasList.tsx";
5	import CanvasPage from "./components/CanvasPage.tsx";
6	
7	type Page =
8	  | { kind: "login" }
9	  | { kind: "signup" }
10	  | { kind: "canvases" }
11	  | { kind: "canvas"; canvasId: string };
12	
13	export default function App() {
14	  const [page, setPage] = useState<Page>(() =>
15	    isAuthenticated() ? { kind: "canvases" } : { kind: "login" }
16	  );
17	
18	  // Reset body margin/padding for full-viewport layout
19	  useEffect(() => {
20	    document.body.style.margin = "0";
21	    document.body.style.padding = "0";
22	    document.body.style.overflow = "hidden";
23	  }, []);
24	
25	  const handleAuth = () => {
26	    setPage({ kind: "canvases" });
27	  };
28	
29	  const handleLogout = () => {
30	    clearAuth();
31	    setPage({ kind: "login" });
32	  };
33	
34	  switch (page.kind) {
35	    case "login":
36	      return <Auth initialMode="login" onAuth={handleAuth} />;
37	
38	    case "signup":
39	      return <Auth initialMode="signup" onAuth={handleAuth} />;
40	
41	    case "canvases":
42	      return (
43	        <CanvasList
44	          onSelectCanvas={(canvasId) => setPage({ kind: "canvas", canvasId })}
45	          onLogout={handleLogout}
46	        />
47	      );
48	
49	    case "canvas":
50	      return (
51	        <CanvasPage
52	          key={page.canvasId}
53	          canvasId={page.canvasId}
54	          onBack={() => setPage({ kind: "canvases" })}
55	          onLogout={handleLogout}
56	        />
57	      );
58	  }
59	}
